      timeout = null;

      isTyping.mutate({ typing: state, channelId });
    }

    return (nextState: boolean) => {
      const shouldTriggerImmediately = nextState !== state;

      state = nextState;
      if (shouldTriggerImmediately) {
        trigger();
      } else {
        timeout ??= setTimeout(trigger, 1000);
      }
    };
  }, [isTyping, channelId]);
