                  className="w-full"
                  external
                >
                  {tier.cta}
                </Button>
              </div>
              <ul
                role="list"
                className={classNames(
                  tier.featured ? 'text-gray-300' : 'text-gray-600',
                  'mt-8 space-y-3 text-sm leading-6 xl:mt-10',
                )}
              >
                {tier.features.map((feature) => (
                  <li key={feature} className="flex gap-x-3">
                    <CheckIcon
                      className={classNames(
                        tier.featured ? 'text-white' : 'text-primary',
                        'h-6 w-5 flex-none',
                      )}
                      aria-hidden="true"
                    />
                    {feature}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      <p className="text-italic text-center text-gray-900">
        Got questions? Do not hesitate to email us at{' '}
        <a href="mailto:info@trpc.io?subject=Pricing">info@trpc.io</a>
      </p>
    </main>
  );
}

  const env = useEnv();

  const ogImg = `${env.OG_URL}/api/docs?${docsParams.toSearchString({
    title: '💸💸💸 Pricing 💸💸💸💸',
    description:
      'Get premium features and support. Support open source. Win-win.',
    permalink: '/pricing',
  })}`;
  return (
    <Layout
      title="Pricing 💸"
      description="Get premium features and support. Support open source. Win-win. tRPC is free to use, but we offer premium plans for teams that need tailored support and features."
    >
      <PageMetadata image={ogImg} />
      <Pricing />
    </Layout>
  );
}

  const { metadata, isBlogPostPage } = useBlogPost();
  const { colorMode } = useColorMode();

  const { frontMatter } = metadata;
  const { commentDiscussionId } = frontMatter;

  return (
    <>
      <BlogPostItem {...props} />
      {commentDiscussionId && isBlogPostPage && (
        <Giscus
          repo="trpc/trpc"
          repoId="MDEwOlJlcG9zaXRvcnkyODA1NTcwNTQ"
          mapping="number"
          term={commentDiscussionId as string}
          strict="0"
          reactionsEnabled="1"
          emitMetadata="1"
          inputPosition="top"
          theme={colorMode}
          lang="en"
        />
      )}
    </>
  );
}

  const { assets, metadata } = useBlogPost();
  const { title, description, date, tags, authors, frontMatter } = metadata;

  const { keywords } = frontMatter;

  const env = useEnv();

  const ogImg = `${env.OG_URL}/api/blog?${blogParams.toSearchString({
    title: metadata.title,
    description: metadata.description,
    authors: authors.map((author) => ({
      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
      name: author.name!,
      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
      title: author.title!,
      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
      img: author.imageURL!,
    })),
    date,
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    readingTimeInMinutes: metadata.readingTime!,
  })}`;

  const image = assets.image ?? frontMatter.image ?? ogImg;

  return (
    <PageMetadata
      title={title}
      description={description}
      keywords={keywords}
      image={image}
    >
      <meta property="og:type" content="article" />
      <meta property="article:published_time" content={date} />
      {/* TODO double check those article meta array syntaxes, see https://ogp.me/#array */}
      {authors.some((author) => author.url) && (
        <meta
          property="article:author"
          content={authors
            .map((author) => author.url)
            .filter(Boolean)
            .join(',')}
        />
      )}
      {tags.length > 0 && (
        <meta
          property="article:tag"
          content={tags.map((tag) => tag.label).join(',')}
        />
      )}
    </PageMetadata>
  );
}

  const pre = useRef(null);
  const [showCopied, setShowCopied] = useState(false);

  const handleCopyCode = () => {
    if (pre.current) {
      void navigator.clipboard.writeText(
        Array.from(pre.current.querySelectorAll('code div.line'))
          .map((el) => el.textContent)
          .join('\n'),
      );
    }
    setShowCopied(true);
    setTimeout(() => {
      setShowCopied(false);
    }, 2000);
  };

  return (
    <pre {...props} ref={pre}>
      {children}
      <button
        type="button"
        aria-label={translate({
          id: 'theme.CodeBlock.copyButtonAriaLabel',
          message: 'Copy code to clipboard',
          description: 'The ARIA label for copy code blocks button',
        })}
        className="copy-button"
        onClick={handleCopyCode}
      >
        {showCopied ? (
          <Translate
            id="theme.CodeBlock.copied"
            description="The copied button label on code blocks"
          >
            Copied
          </Translate>
        ) : (
          <Translate
            id="theme.CodeBlock.copy"
            description="The copy button label on code blocks"
          >
            Copy
          </Translate>
        )}
      </button>
    </pre>
  );
}

  if (pre.current) {
    void navigator.clipboard.writeText(
      Array.from(pre.current.querySelectorAll('code div.line'))
        .map((el) => el.textContent)
        .join('\n'),
    );
  }
  setShowCopied(true);
  setTimeout(() => {
    setShowCopied(false);
  }, 2000);
}

  const { metadata, frontMatter, assets } = useDoc();
  const { title, description } = metadata;

  const env = useEnv();

  const ogImg = `${env.OG_URL}/api/docs?${docsParams.toSearchString({
    title,
    description,
    permalink: metadata.permalink,
  })}`;
  return (
    <PageMetadata
      title={metadata.title}
      description={metadata.description}
      keywords={frontMatter.keywords}
      image={assets.image ?? frontMatter.image ?? ogImg}
    />
  );
}

  const location = useLocation();

  const globalData = useGlobalData();

  const versions: Version[] = (
    globalData['docusaurus-plugin-content-docs'] as any
  ).default.versions;

  const byLabel = {} as Record<VersionLabel, Version>;
  for (const version of versions) {
    byLabel[version.label] = version;
  }

  const currentVersion: Version =
    versions
      .filter((it) => it.path !== '/docs')
      .find((it) => location.pathname.startsWith(it.path)) ??
    versions.find((it) => it.isLast) ??
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    versions[0]!;

  return {
    currentVersion,
    byLabel,
  };
}

  const versions = useTypedVersion();

  switch (versions.currentVersion.label) {
    case '11.x': {
      return null;
    }
    case '10.x':
    case '9.x':
    default: {
      return <DocVersionBanner {...props} />;
    }
  }
}

  const history = useHistory();

  return (
    <div
      onContextMenu={(e) => {
        e.preventDefault();
        history.push({ pathname: '/media' });
      }}
    >
      <Logo {...props} />
    </div>
  );
}

  const envSchema = z.object({
    VERCEL_URL: z
      .string()
      .transform((url) => (!url.startsWith('http') ? `https://${url}` : url))
      .default('http://localhost:3000'),
    VERCEL_ENV: z
      .enum(['production', 'preview', 'development'])
      .default('development'),
    VERCEL_GIT_COMMIT_REF: z
      .string()
      .default('n/a')
      .transform((ref) => ref.replace('/', '-')),
    TYPEDOC: booleanSchema.default(true),
  });

  const env = envSchema.parse(input);

  if (!env.TYPEDOC) {
    console.log('ℹ️ℹ️ℹ️ℹ️ℹ️ Skipping typedoc');
  }

  function getOG_URL() {
    switch (env.VERCEL_ENV) {
      case 'production':
      case 'preview':
        return 'https://og-image.trpc.io';
      // FIXME: this gets cached across deployments for some reason
      // case 'preview':
      //   return `https://og-image-git-${env.VERCEL_GIT_COMMIT_REF}-trpc.vercel.app`;
      case 'development':
        return 'http://localhost:3001';
      default:
        throw new Error("Can't happen");
    }
  }

  const OG_URL = getOG_URL();
  // console.log({ OG_URL });
  return {
    ...env,
    OG_URL,
  };
}

  switch (env.VERCEL_ENV) {
    case 'production':
    case 'preview':
      return 'https://og-image.trpc.io';
    // FIXME: this gets cached across deployments for some reason
    // case 'preview':
    //   return `https://og-image-git-${env.VERCEL_GIT_COMMIT_REF}-trpc.vercel.app`;
    case 'development':
      return 'http://localhost:3001';
    default:
      throw new Error("Can't happen");
  }
}

  const isModifiedEvent = !!(e.metaKey || e.altKey || e.ctrlKey || e.shiftKey);

  const shouldProcessLinkClick =
    e.button === 0 && // Ignore everything but left clicks
    !isModifiedEvent; // Ignore clicks with modifier keys ;

  if (shouldProcessLinkClick) {
    e.preventDefault();

    const href = e.currentTarget.href;

    const id = href.split('#')[1];

    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    const section = document.getElementById(id!);
    section?.scrollIntoView({ behavior: 'smooth' });

    window.history.pushState(null, '', href);
  }
}

  return Object.entries(obj)
    .map(([key, value]) => {
      const values = isArray(value) ? value : [value];

      return values.map((v) => `${key}=${encodeURIComponent(v)}`).join('&');
    })
    .join('&');
}

  const { siteConfig } = useDocusaurusContext();
  const customFields = siteConfig.customFields!;

  const env = customFields.env;

  return env as Env;
}
